                            <div class="w-full progress-bar-bg rounded-full h-2.5"><div class="bg-green-500 h-2.5 rounded-full" style="width: ${lifePercent}%"></div></div>
                        </div>
                        <div>
                            <div class="flex justify-between mb-1"><span>Linh lực:</span><span class="font-mono highlight-value">${manaMatch[1]} / ${manaMatch[2]}</span></div>
                            <div class="w-full progress-bar-bg rounded-full h-2.5"><div class="bg-blue-500 h-2.5 rounded-full" style="width: ${manaPercent}%"></div></div>
                        </div>
                        <p><span class="font-semibold text-gray-400">Trạng thái: </span><span class="text-green-400">${kvs['Trạng thái'] || 'Bình thường'}</span></p>
                    </div>
                </div>
                <div class="mt-4 flex items-center justify-between flex-wrap gap-2">
                    <div>
                        <span class="text-lg text-yellow-400">Cảnh giới: </span>
                        <span class="text-2xl font-semibold text-white">${realmParts[1] || ''}</span>
                        <span class="text-xl text-yellow-300">${realmParts[2] || ''}</span>
