            const repContent = `<div class="scrollable-content">${repListHtml}</div>`;
            let itemListHtml = (data.core['Vật phẩm mang theo'].length === 0) ? `<div class="text-center text-gray-400 italic p-4">Túi đồ trống</div>` : `<ul class="space-y-2 text-sm">${data.core['Vật phẩm mang theo'].map(i => `<li class="p-2 bg-black/10 rounded-md"><span class="highlight-value">${i.key}:</span> ${i.value}</li>`).join('')}</ul>`;
