                    </div>`;
        }

        function renderSkillsPanel() {
            const tabs = ['Công pháp', 'Thần thông', 'Pháp bảo'].map(title => {
                const items = data.skills[title];
                let content = `<div class="scrollable-content space-y-4">`;
