            function createTaskHtml(title, taskData) {
                if (!taskData || taskData.length === 0 || (taskData[0] && taskData[0].key === 'Nhiệm vụ: Chưa có')) {
                    return `<div><h3 class="text-lg font-semibold text-violet-400 mb-2">【${title}】</h3><p class="text-gray-400 italic">Chưa có</p></div>`;
