                return `<div><h3 class="text-lg font-semibold text-violet-400 mb-2">【${title}】</h3><div class="space-y-2">${taskContent}</div></div>`;
            }

            const mainTaskHtml = createTaskHtml('Nhiệm vụ chính', data.system['Nhiệm vụ chính']);

            const otherTasks = [
                createTaskHtml('Nhiệm vụ phụ', data.system['Nhiệm vụ phụ']),
                createTaskHtml('Nhiệm vụ khẩn cấp', data.system['Nhiệm vụ khẩn cấp']),
                createTaskHtml('Nhiệm vụ độc quyền', data.system['Nhiệm vụ độc quyền']),
                createTaskHtml('Nhiệm vụ thiên khiển', data.system['Nhiệm vụ thiên khiển'])
            ].filter(html => !html.includes('Chưa có</p>')).join('<div class="my-4 border-t border-violet-500/20"></div>'); // Chỉ thêm vào và dùng đường kẻ phân cách khi có nội dung

            return `<div class="section-divider"></div>
                <section class="p-6 rounded-lg special-section">
                    <h2 class="text-2xl font-bold text-violet-300 panel-title mb-4">Tiệm tạp hóa của MudShooter</h2>
