                        <p>Điểm hệ thống: <span class="text-green-300 font-mono">${kvs['Điểm hệ thống'] || 0}</span></p>
                        <p>Hệ thống phụ: <span class="text-cyan-300">${kvs['Hệ thống phụ'] || 'Không có'}</span></p>
                    </div>
                    <div class="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4">
                         <div>${mainTaskHtml}</div>
                         <div class="space-y-4">${otherTasks}</div>
                    </div>
                </section>`;
        }

        container.querySelector('#core-panel-target').innerHTML = renderCorePanel();
        container.querySelector('#core-subpanel-target').innerHTML = renderCoreSubPanel();
        container.querySelector('#skills-panel-target').innerHTML = renderSkillsPanel();
        container.querySelector('#attributes-panel-target').innerHTML = renderAttributesPanel();
        container.querySelector('#relations-panel-target').innerHTML = renderRelationsPanel();
        container.querySelector('#system-panel-wrapper').innerHTML = renderSystemPanel();

        const radarCanvas = container.querySelector('#radar-chart');
        if(radarCanvas){
            const basicAttrValues = {'Căn cốt':0,'Ngộ tính':0,'Trí tuệ':0,'Chỉ số cảm xúc':0,'Mị lực':0};
            const basicAttributesData = data.attributes['Thuộc tính cơ bản'];
            basicAttributesData.forEach(attr => {
                if (basicAttrValues.hasOwnProperty(attr.key)) {
                    basicAttrValues[attr.key] = parseInt(attr.value) || 0;
                }
            });
            new Chart(radarCanvas.getContext('2d'), {
                type: 'radar', data: { labels: Object.keys(basicAttrValues), datasets: [{ label: 'Thuộc tính cơ bản', data: Object.values(basicAttrValues), backgroundColor: 'rgba(209, 159, 84, 0.2)', borderColor: 'rgba(209, 159, 84, 1)', pointBackgroundColor: 'rgba(209, 159, 84, 1)' }] },
                options: { responsive: true, maintainAspectRatio: false, scales: { r: { angleLines: { color: 'rgba(255, 255, 255, 0.2)' }, grid: { color: 'rgba(255, 255, 255, 0.2)' }, pointLabels: { color: '#e0e1e6', font: { family: "'Noto Serif SC', serif", size: 12 } }, suggestedMin: 0, suggestedMax: 100 } }, plugins: { legend: { display: false } } }
            });
        }

        container.querySelectorAll('.nested-tabs-container').forEach(tabContainer => {
            tabContainer.addEventListener('click', e => {
                const button = e.target.closest('.tab-button');
                if (!button) return;
                tabContainer.querySelectorAll('.tab-button').forEach(btn => btn.classList.remove('active'));
                button.classList.add('active');
                const targetId = button.dataset.tab;
                tabContainer.querySelectorAll('.tab-content').forEach(content => { content.id === targetId ? content.classList.add('active') : content.classList.remove('active'); });
            });
        });
    })();
    </script>
