            let systemHtml = `<div class="card"><div class="card-header">MudShooter的小卖部</div><div class="info-item">${Object.entries(data.system.kvs).map(([k,v])=>`<b>${k}:</b> ${v}`).join('<br>')}</div></div>`;
            systemHtml += renderListBlock('主线任务', data.system.主线任务);
            systemHtml += renderListBlock('支线任务', data.system.支线任务);
            container.querySelector('#system-panel').innerHTML = systemHtml;

            // 雷达图
            new Chart(container.querySelector('#radar-chart').getContext('2d'), {
                type: 'radar', data: { labels: Object.keys(basicAttrValues), datasets: [{ label: '基础属性', data: Object.values(basicAttrValues), backgroundColor: 'rgba(97, 175, 239, 0.2)', borderColor: 'rgba(97, 175, 239, 1)' }] },
                options: { responsive: true, maintainAspectRatio: false, scales: { r: { angleLines: { color: 'rgba(255, 255, 255, 0.2)' }, grid: { color: 'rgba(255, 255, 255, 0.2)' }, pointLabels: { color: '#e0e1e6', font: { family: "'Yu Mincho', '游明朝体', 'Noto Serif SC', serif", size: 12 } }, suggestedMin: 0 } }, plugins: { legend: { display: false } } }
            });

            // --- 交互事件 ---
            container.querySelector('.status-header').addEventListener('click', (e) => {
                const content = container.querySelector('.status-content');
                content.classList.toggle('collapsed');
                e.currentTarget.querySelector('.collapse-btn').textContent = content.classList.contains('collapsed') ? '[ 展开 ]' : '[ 收起 ]';
