// ==UserScript==
// @name         自动掷骰脚本
// @version      2.0
// @description  在用户发送消息或重新生成时，自动为战斗判定生成一个真实的1-100随机数。
// @author       Woup
// ==/UserScript==

(function () {
    // 这是一个核心函数，封装了掷骰、储存和通知的全部逻辑。
    const rollDiceAndNotify = async () => {
        // 1. 生成一个1到100之间的整数作为随机数。
        const diceResult = Math.floor(Math.random() * 100) + 1;

        // 2. 将随机数覆盖式地存入聊天变量 'dice.rollResult'。
        //    这确保了每次生成使用的都是全新的、即时的随机数。
        await updateVariablesWith(
            (vars) => {
                _.set(vars, 'dice.rollResult', diceResult);
                return vars;
            }, {
                type: 'chat'
            }
        );

        // 3. 通过弹窗通知用户本次行动的掷骰结果。
        toastr.success(`骰子已掷出: ${diceResult}`, '本次判定值');

        console.log(`[自动掷骰脚本] 在生成开始前掷骰: ${diceResult}。`);
    };

    // 监听SillyTavern的“生成开始”事件。
    // 这个事件会在发送、重生成、滑动等多种操作时触发。
    eventOn(tavern_events.GENERATION_AFTER_COMMANDS, (type, option, dry_run) => {
        // 'dry_run' 表示这是一个模拟运行，例如提示词查看器，我们不应在这种情况下掷骰。
        if (dry_run) {
            console.log('[自动掷骰脚本] 检测到 dry_run，跳过本次自动掷骰。');
            return;
        }

        // 'quiet' 类型的生成通常是其他扩展的后台任务，我们也不需要为其掷骰。
        if (type === 'quiet') {
             console.log(`[自动掷骰脚本] 检测到 'quiet' 生成类型，跳过本次自动掷骰。`);
             return;
        }

        // 对于所有其他由用户直接发起的生成请求，都执行掷骰逻辑。
        rollDiceAndNotify();
    });

})();

// ==UserScript==
// @name         战斗掷骰脚本
// @version      1.0
// @description  为战斗判定生成一个真实的1-100随机数。
// @author       Woup
// ==/UserScript==

(function () {
    // 脚本加载时，立即在用户输入栏创建“掷骰子”按钮
    // 这个按钮只会在当前脚本启用时显示
    replaceScriptButtons(getScriptId(), [{
        name: '掷骰子',
        visible: true
    }]);

    // 监听“掷骰子”按钮的点击事件
    eventOn(getButtonEvent('掷骰子'), async () => {
        // --- 核心逻辑 ---

        // 1. 生成一个1到100之间的整数作为随机数
        const diceResult = Math.floor(Math.random() * 100) + 1;

        // 2. 将随机数储存在聊天变量中
        // 我们使用 'dice.rollResult' 作为变量路径，结构清晰
        // 'type: 'chat'' 表示这是一个聊天级别的变量，只在当前对话中有效
        await updateVariablesWith(
            (vars) => {
                _.set(vars, 'dice.rollResult', diceResult);
                return vars;
            }, {
                type: 'chat'
            }
        );

        // 3. 通过弹窗通知用户掷骰结果，提供即时反馈
        toastr.success(`骰子已掷出: ${diceResult}`, '判定值已储存');

        console.log(`[战斗掷骰脚本] 生成随机数: ${diceResult}，已存入聊天变量 'dice.rollResult'。`);
    });

})();
